patch:
--- a/counter_with_reset.v
+++ b/counter_with_reset.v
@@ -1,13 +1,13 @@
 module counter_with_reset (
   input clk,
   input rst_n,
   output reg [15:0] count
 );

-  always @(posedge clk) begin
+  always @(posedge clk or negedge rst_n) begin
     if (!rst_n)
       count <= 16'b0;
     else
       count <= count + 1;
   end

 endmodule

before_code:
module counter_with_reset (
  input clk,
  input rst_n,
  output reg [15:0] count
);

  always @(posedge clk) begin
    if (!rst_n)
      count <= 16'b0;
    else
      count <= count + 1;
  end

endmodule

after_code:
module counter_with_reset (
  input clk,
  input rst_n,
  output reg [15:0] count
);

  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      count <= 16'b0;
    else
      count <= count + 1;
  end

endmodule
